package main

import (
	"net/http"
	"strings"
)

// isAllowedHost — список разрешённых хостов для исходящих запросов.
func isAllowedHost(host string) bool {
	allowed := []string{"api.example.com", "status.example.com"}
	for _, h := range allowed {
		if strings.EqualFold(host, h) {
			return true
		}
	}
	return false
}

func proxyHandler(w http.ResponseWriter, r *http.Request) {
	target := r.URL.Query().Get("url")
	// TODO(уязвимо): URL не валидируется (схема + allowlist хоста), запрос идёт без таймаута.
	// Распарсьте URL, проверьте u.Scheme и isAllowedHost(u.Hostname()), используйте http.Client{Timeout}.
	resp, err := http.Get(target)
	if err != nil {
		http.Error(w, "request failed", http.StatusInternalServerError)
		return
	}
	defer resp.Body.Close()
	w.WriteHeader(http.StatusOK)
}
